mapper.select:
select u.*, d.dept_id, d.title, d.specialty, d.work_time, d.daily_max_num, dp.dept_name from sys_user u left join hospital_doctor d on u.id = d.user_id left join hospital_department dp on d.dept_id = dp.id
u.role_id = 2
and u.username like concat('%',#{username},'%')
and u.phone like concat('%',#{phone},'%')
and u.identity_card like concat('%',#{identityCard},'%')
and u.real_name like concat('%',#{realName},'%')
and dp.dept_name like concat('%',#{deptName},'%')
and d.dept_id = #{deptId}
and d.work_time = #{workTime}
and d.daily_max_num = #{dailyMaxNum}
and u.status = #{status}

